'use server';

import pool from '@/lib/db';
import { RowDataPacket } from 'mysql2';

export interface AbsenceRecord {
  date: string;
  dayOfWeek: string;
  driverName: string;
  vehicleNumber: string;
  phone: string;
  dockNumber: string;
}

export async function getAbsenceData(startDate: string, endDate: string) {
  let connection;
  try {
    connection = await pool.getConnection();

    // 1. Fetch Drivers (Filter by Dock Number 01~40 in logic)
    // We select all potentially valid drivers first
    const [drivers] = await connection.execute<RowDataPacket[]>(`
      SELECT CB_DRIVER, CA_NAME, CA_NO, CA_HP, CA_DOCKNO
      FROM t_car 
      WHERE CA_DOCKNO IS NOT NULL 
        AND CA_DOCKNO != ''
        AND CA_NO IS NOT NULL
        AND CA_NO != ''
    `);

    // Filter by Dock Range 1~40 (User Guide: 01~40, including 01-1 etc)
    const targetDrivers = drivers.filter((d: any) => {
      const dockStr = d.CA_DOCKNO || '';
      if (!dockStr) return false;
      
      // Extract prefix before '-' if exists
      const prefix = dockStr.split('-')[0];
      const num = parseInt(prefix, 10);
      
      // Check range 1 to 40
      return !isNaN(num) && num >= 1 && num <= 40;
    });

    // 2. Fetch Dispatches in Date Range
    const [dispatches] = await connection.execute<RowDataPacket[]>(`
      SELECT DISTINCT O_DATE, CB_DRIVER 
      FROM t_out 
      WHERE O_DATE BETWEEN ? AND ?
    `, [startDate, endDate]);

    // 3. Process Absence
    const absenceList: AbsenceRecord[] = [];
    const dispatchMap = new Set<string>();

    dispatches.forEach((d: any) => {
      const dateStr = formatDate(new Date(d.O_DATE));
      dispatchMap.add(`${dateStr}|${d.CB_DRIVER}`);
    });

    const start = new Date(startDate);
    const end = new Date(endDate);

    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      const day = d.getDay();
      // Mon(1) ~ Fri(5)
      if (day === 0 || day === 6) continue;

      const dateStr = formatDate(d);
      const dayOfWeekStr = getDayOfWeek(d);

      for (const driver of targetDrivers) {
        const driverName = driver.CB_DRIVER;
        const key = `${dateStr}|${driverName}`;

        if (!dispatchMap.has(key)) {
          absenceList.push({
            date: dateStr,
            dayOfWeek: dayOfWeekStr,
            driverName: driverName,
            vehicleNumber: driver.CA_NO,
            phone: driver.CA_HP || '',
            dockNumber: driver.CA_DOCKNO
          });
        }
      }
    }

    return absenceList;

  } catch (error) {
    console.error('Database Error:', error);
    throw new Error('Failed to fetch absence data');
  } finally {
    if (connection) connection.release();
  }
}

function formatDate(date: Date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

function getDayOfWeek(date: Date) {
  const days = ['일', '월', '화', '수', '목', '금', '토'];
  return days[date.getDay()];
}
